# BEST PRACTICE: Multi-pattern approach with caching + fallback
import hashlib
import time
from enum import Enum

class CricketBowler(Enum):
    PACE_ATTACK = "gpt-4"        # Premium, high-cost
    SPIN_BOWLER = "gpt-3.5"      # Mid-tier fallback
    DEFENSIVE = "davinci-003"    # Budget fallback

class LLMBattingLineup:
    def __init__(self, cache_ttl_seconds=3600):
        self.bowling_cache = {}  # Response cache
        self.cache_ttl = cache_ttl_seconds
        self.delivery_queue = []  # Request queue

    def hash_cricket_question(self, question: str) -> str:
        """Hash the question to create cache key"""
        return hashlib.md5(question.encode()).hexdigest()

    def query_batting_stats(self, question: str, bowler_preference=CricketBowler.PACE_ATTACK) -> dict:
        """Best practice: Try cache first, then cascade through bowlers"""
        cache_key = self.hash_cricket_question(question)

        # Check cache (avoid redundant API calls)
        if cache_key in self.bowling_cache:
            cached_entry = self.bowling_cache[cache_key]
            if time.time() - cached_entry['timestamp'] < self.cache_ttl:
                return {**cached_entry['response'], 'source': 'cache_hit'}

        # Try preferred bowler first, then fallback cascade
        bowlers_to_try = [
            bowler_preference,
            CricketBowler.SPIN_BOWLER,
            CricketBowler.DEFENSIVE
        ]

        for bowler in bowlers_to_try:
            try:
                response = self._call_api(question, bowler)
                # Cache the successful response
                self.bowling_cache[cache_key] = {
                    'response': response,
                    'timestamp': time.time()
                }
                return {**response, 'bowler_used': bowler.value}
            except Exception as e:
                print(f"Bowler {bowler.value} failed: {e}, trying backup...")
                continue

        # All bowlers failed, return cached response regardless of TTL
        if cache_key in self.bowling_cache:
            return {**self.bowling_cache[cache_key]['response'], 'source': 'stale_cache'}

        raise Exception("All bowling lineup exhausted")

    def _call_api(self, question: str, bowler: CricketBowler) -> dict:
        """Simulate API call to specific model"""
        # Real implementation would use requests/openai library
        return {'answer': f'Response from {bowler.value}', 'tokens': 150}

# ANTI-PATTERN: No caching, no fallback, synchronous blocking
class PoorBattingLineup:
    def query_batting_stats_antipattern(self, question: str) -> dict:
        """Anti-pattern: Always call expensive model, no resilience"""
        # Every identical question hits the API (wasteful)
        # No fallback if gpt-4 fails (fragile)
        response = self._call_gpt4_only(question)
        return response  # Blocks until complete (slow UX)

    def _call_gpt4_only(self, question: str) -> dict:
        # Single point of failure, no degradation strategy
        return {'answer': 'expensive response'}

# BEST PRACTICE: Streaming pattern for interactive apps
class StreamingCricketCommentary:
    def stream_match_analysis(self, prompt: str):
        """Yield tokens as they arrive instead of waiting for completion"""
        # Simulates streaming API call (e.g., OpenAI streaming mode)
        for token in self._get_streaming_response(prompt):
            yield token  # User sees response in real-time
            time.sleep(0.05)  # Simulate network delay

    def _get_streaming_response(self, prompt: str):
        return "Virat Kohli has walked to the crease with an aggressive stance...".split()

# Usage
lineup = LLMBattingLineup(cache_ttl_seconds=3600)
result1 = lineup.query_batting_stats("What is Kohli's average against pace?")  # Calls API
result2 = lineup.query_batting_stats("What is Kohli's average against pace?")  # Cache hit

streaming = StreamingCricketCommentary()
for token in streaming.stream_match_analysis("Describe this over"):
    print(token, end=' ', flush=True)  # Real-time output

import anthropic
import time
from functools import wraps
from datetime import datetime, timedelta

class CricketAnalysisAPI:
    """Production-grade LLM integration following enterprise patterns."""

    def __init__(self, api_key: str, max_retries: int = 3):
        self.client = anthropic.Anthropic(api_key=api_key)
        self.max_retries = max_retries
        self.rate_limit_window = {}
        self.circuit_breaker_state = "CLOSED"
        self.failure_count = 0
        self.failure_threshold = 5

    def analyze_batting_performance(self, player_stats: dict) -> str:
        """Analyze cricket performance with automatic retry and circuit breaking."""

        # Circuit breaker check
        if self.circuit_breaker_state == "OPEN":
            raise Exception("Service temporarily unavailable - circuit open")

        for attempt in range(self.max_retries):
            try:
                prompt = f"""Analyze this cricket player's performance:
                Runs: {player_stats['runs']}
                Matches: {player_stats['matches']}
                Average: {player_stats['average']}
                Strike Rate: {player_stats['strike_rate']}"""

                message = self.client.messages.create(
                    model="claude-3-5-sonnet-20241022",
                    max_tokens=1024,
                    messages=[{"role": "user", "content": prompt}]
                )

                # Reset failure counter on success
                self.failure_count = 0
                return message.content[0].text

            except anthropic.RateLimitError:
                wait_time = (2 ** attempt) + (time.time() % 1)  # Exponential backoff
                if attempt < self.max_retries - 1:
                    time.sleep(wait_time)
                    continue
                raise

            except anthropic.APIError as e:
                self.failure_count += 1
                if self.failure_count >= self.failure_threshold:
                    self.circuit_breaker_state = "OPEN"
                if attempt == self.max_retries - 1:
                    raise
                time.sleep(2 ** attempt)

    def batch_analysis(self, players_list: list) -> dict:
        """Process multiple players respecting rate limits."""
        results = {}
        for player_id, stats in players_list:
            # Token bucket rate limiting
            self._rate_limit_check()
            try:
                results[player_id] = self.analyze_batting_performance(stats)
            except Exception as e:
                results[player_id] = f"Error: {str(e)}"
        return results

    def _rate_limit_check(self):
        """Implement token bucket algorithm (100 req/min)."""
        now = datetime.now()
        window_start = now - timedelta(minutes=1)

        self.rate_limit_window = {
            k: v for k, v in self.rate_limit_window.items()
            if v > window_start
        }

        if len(self.rate_limit_window) >= 100:
            sleep_time = 60 - (now - min(self.rate_limit_window.values())).total_seconds()
            if sleep_time > 0:
                time.sleep(sleep_time)

        self.rate_limit_window[str(now)] = now

# Production usage
if __name__ == "__main__":
    api = CricketAnalysisAPI(api_key="your-api-key")

    player_stats = {
        "runs": 5847,
        "matches": 92,
        "average": 63.54,
        "strike_rate": 87.3
    }

    analysis = api.analyze_batting_performance(player_stats)
    print(analysis)
